mapper.select:
SELECT
    /* 1. 절감량 및 나무 효과: STATUS가 'Y'인 데이터만 합산 */
    SUM(CASE WHEN TOTAL.STATUS = 'Y' THEN NVL(TOTAL.CO2_REDUCTION_G, 0) ELSE 0 END) AS co2,
    SUM(CASE WHEN TOTAL.STATUS = 'Y' THEN NVL(TOTAL.TREE_EFFECT, 0) ELSE 0 END) AS tree,

    /* 2. 퀴즈 성공 횟수: ACT_TYPE이 QUIZ로 시작하고 STATUS가 'Y'인 것 카운트 */
    COUNT(CASE WHEN TOTAL.ACT_TYPE LIKE 'QUIZ_%' AND TOTAL.STATUS = 'Y' THEN 1 END) AS quizSuccessCount,

    /* 3. 퀴즈 실패 횟수: ACT_TYPE이 QUIZ로 시작하고 STATUS가 'N'인 것 카운트 */
    COUNT(CASE WHEN TOTAL.ACT_TYPE LIKE 'QUIZ_%' AND TOTAL.STATUS = 'N' THEN 1 END) AS quizFailCount
FROM (
         /* 퀴즈 기록 (성공/실패 모두 포함) */
         SELECT H.MEMBER_ID, H.STATUS, H.ACTIVITY_TYPE AS ACT_TYPE, Q.CO2_REDUCTION_G, Q.TREE_EFFECT
         FROM INTEGRATED_HISTORY H
                  JOIN QUIZ Q ON H.REF_ID = Q.QUIZ_NO
         WHERE H.ACTIVITY_TYPE LIKE 'QUIZ_%'

         UNION ALL

         /* 퀘스트 기록 (성공/실패 모두 포함) */
         SELECT H.MEMBER_ID, H.STATUS, H.ACTIVITY_TYPE AS ACT_TYPE, QS.CO2_REDUCTION_G, QS.TREE_EFFECT
         FROM INTEGRATED_HISTORY H
                  JOIN QUEST QS ON H.REF_ID = QS.QUEST_NO
         WHERE H.ACTIVITY_TYPE = 'QUEST'
     ) TOTAL
WHERE TOTAL.MEMBER_ID = #{memberId}
